python3 - << 'EOF'
# Final comprehensive validation
import json
from datetime import datetime, timezone, timedelta
from zoneinfo import ZoneInfo

TZ = ZoneInfo("Asia/Shanghai")
UTC = timezone.utc

def parse_ical_dt(s):
    s = s.strip()
    if s.endswith("Z"):
        return datetime.strptime(s, "%Y%m%dT%H%M%SZ").replace(tzinfo=UTC)
    return datetime.strptime(s, "%Y%m%dT%H%M%S").replace(tzinfo=UTC)

# Load scheduled.ics
with open('/tmp_workspace/results/scheduled.ics') as f:
    content = f.read()

# Parse all new events
events = []
blocks = content.split("BEGIN:VEVENT")
for block in blocks[1:]:
    ev = {}
    for line in block.splitlines():
        line = line.strip()
        if line.startswith("UID:"): ev["uid"] = line[4:]
        elif line.startswith("SUMMARY:"): ev["summary"] = line[8:]
        elif line.startswith("DTSTART:"): ev["start"] = parse_ical_dt(line[8:]).astimezone(TZ)
        elif line.startswith("DTEND:"): ev["end"] = parse_ical_dt(line[6:]).astimezone(TZ)
        elif line.startswith("ATTENDEE"): ev.setdefault("attendees", []).append(line.split("mailto:")[-1])
    if "start" in ev:
        events.append(ev)

print(f"Total VEVENTs: {len(events)}")

# Validate no original events modified (check by UID)
orig_count = sum(1 for e in events if e["uid"].startswith("orig-"))
new_count  = sum(1 for e in events if "req_" in e["uid"])
print(f"Original events: {orig_count} (expect 30)")
print(f"New events:      {new_count} (expect 10)")

# Validate: no new meeting overlaps with any other event for shared attendees
new_events = [e for e in events if "req_" in e["uid"]]
all_events = events

print("\nChecking new meetings for conflicts:")
errors = 0
